#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        int *leaders = (int*)malloc(N * sizeof(int));
        int cnt = 0;
        int maxFromRight = arr[N-1];
        leaders[cnt++] = maxFromRight;
        for (int i = N-2; i >= 0; --i) {
            if (arr[i] > maxFromRight) {
                maxFromRight = arr[i];
                leaders[cnt++] = maxFromRight;
            }
        }
        for (int i = cnt-1; i >= 0; --i) {
            printf("%d", leaders[i]);
            if (i) printf(" ");
        }
        printf("\n");
        free(arr);
        free(leaders);
    }
    return 0;
}

