int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        for (int &x : a) cin >> x;
        vector<int> leaders;
        int maxFromRight = a.back();
        leaders.push_back(maxFromRight);
        for (int i = N - 2; i >= 0; --i) {
            if (a[i] > maxFromRight) {
                maxFromRight = a[i];
                leaders.push_back(maxFromRight);
            }
        }
        for (int i = (int)leaders.size() - 1; i >= 0; --i) {
            cout << leaders[i];
            if (i) cout << ' ';
        }
        cout << '\n';
    }
    return 0;
}

