const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = parseInt(input[idx++], 10);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(input[idx++], 10);
  const arr = new Array(N);
  for (let i = 0; i < N; i++) arr[i] = parseInt(input[idx++], 10);
  const leaders = [];
  let maxFromRight = arr[N - 1];
  leaders.push(maxFromRight);
  for (let i = N - 2; i >= 0; i--) {
    if (arr[i] > maxFromRight) {
      maxFromRight = arr[i];
      leaders.push(maxFromRight);
    }
  }
  outputs.push(leaders.reverse().join(' '));
}
process.stdout.write(outputs.join('\n'));
